import{_ as t,c as o,o as r,ah as n}from"./chunks/framework.RCw5T9E9.js";const u=JSON.parse('{"title":"Release history","description":"","frontmatter":{"title":"Release history"},"headers":[],"relativePath":"releases/history.md","filePath":"releases/history.md"}'),s={name:"releases/history.md"};function i(a,e,l,d,g,h){return r(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="release-history" tabindex="-1">Release history <a class="header-anchor" href="#release-history" aria-label="Permalink to &quot;Release history&quot;">​</a></h1><h2 id="_2-0-0-2026-01-23" tabindex="-1">[2.0.0] - 2026-01-23 <a class="header-anchor" href="#_2-0-0-2026-01-23" aria-label="Permalink to &quot;[2.0.0] - 2026-01-23&quot;">​</a></h2><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>Corporate-friendly build that does not require installation.</li><li>Version tracking and notifications for new updates.</li><li>Project moved to an <strong>iframe</strong> entry; <strong>popup</strong> is no longer the primary entry point.</li></ul><hr><h3 id="performance" tabindex="-1">Performance <a class="header-anchor" href="#performance" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Fixed a memory spike on static sites, including Docusaurus and Hugo.</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Refreshed styles and overall visual design.</li></ul><h2 id="_2-1-0-2026-02-02" tabindex="-1">[2.1.0] - 2026-02-02 <a class="header-anchor" href="#_2-1-0-2026-02-02" aria-label="Permalink to &quot;[2.1.0] - 2026-02-02&quot;">​</a></h2><h3 id="core-1" tabindex="-1">Core <a class="header-anchor" href="#core-1" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li>New <strong>Network</strong> management tab.</li><li>Redesign for <strong>iframe</strong> layout instead of <strong>popup</strong> — more useful space on screen.</li><li>JSON layout tweaks — editor uses full app height.</li><li>Fixed tabs sticking when opening early — <strong>Props</strong> and <strong>Pinia</strong> no longer require a full page reload to appear.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Fixed favorites not resolving after reload or repeated flows.</li><li>Optimized Props for long sessions without excessive CPU; internal refactor.</li><li>Props tab overhaul — better behavior with large trees and hover search.</li><li>Removed <strong>Props only</strong> mode.</li></ul><hr><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Intercepts <strong>fetch</strong> and <strong>XMLHttpRequest</strong> except <strong>OPTIONS</strong> and extension-originated calls.</li><li>Summary columns: status, method, name, duration, size.</li><li>Detailed view: params, auth, headers, request, response — only CORS-exposed headers where applicable.</li><li>Pause/resume capture; recording on by default on first open.</li><li><strong>Breakpoint</strong> — pause and edit outbound requests before send.</li><li><strong>Mock Response</strong> — intercept and return a synthetic response.</li><li>Quick copy of URLs, tokens, and key fields.</li><li>Clear all captured requests.</li><li>Event-driven architecture without polling for lower CPU.</li><li>Binary detection — textual preview suppressed with metadata only.</li></ul><h2 id="_2-2-0-2026-02-24" tabindex="-1">[2.2.0] - 2026-02-24 <a class="header-anchor" href="#_2-2-0-2026-02-24" aria-label="Permalink to &quot;[2.2.0] - 2026-02-24&quot;">​</a></h2><h3 id="core-2" tabindex="-1">Core <a class="header-anchor" href="#core-2" aria-label="Permalink to &quot;Core&quot;">​</a></h3><ul><li><p><strong>Display Mode</strong> — move the app into a <strong>DevTools</strong> tab or disable pure overlay.</p></li><li><p><strong>Options</strong> reorganized into logical sections.</p></li><li><p><strong>Props</strong>, <strong>Pinia Store</strong>, and <strong>Network</strong> filters editable inline without jumping to Options.</p></li><li><p>Fixed JSON text-mode click target area.</p></li><li><p>Large JSON no longer truncates — heavy CSS disabled for performance.</p></li><li><p>Update notifications revised:</p><ul><li><strong>Dismiss</strong> → <strong>Later</strong>;</li><li><strong>Download</strong> → <strong>Preview</strong> pointing to <strong>Options → About</strong>;</li><li>detail block with <strong>Ignore</strong> and <strong>Download</strong>.</li></ul></li></ul><hr><h3 id="props-1" tabindex="-1">Props <a class="header-anchor" href="#props-1" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Fixed missing Props hover highlight in <strong>Standalone</strong>.</li></ul><hr><h3 id="network-1" tabindex="-1">Network <a class="header-anchor" href="#network-1" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><strong>form-data</strong> support for reading and traffic substitution.</li><li>Saved files for reuse with <strong>Breakpoint</strong> / <strong>form-data</strong>.</li><li><strong>Rewrite Breakpoint</strong> / <strong>Rewrite Mock</strong> — overwrite existing rules instead of duplicating.</li><li>Badges for active <strong>Breakpoint</strong> / <strong>Mock</strong> per request; click opens matching Options.</li><li>Search by HTTP status code.</li><li><strong>Breakpoint</strong> rules consider HTTP method.</li><li>Fixed inspector not opening when a <strong>breakpoint</strong> fired.</li><li>Context menu entries: <strong>Disable/Enable Breakpoint</strong>, <strong>Disable/Enable Mock</strong>, <strong>Delete Breakpoint/Mock</strong> (shown when applicable).</li></ul><hr><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><h4 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h4><ul><li>Core settings (<strong>Display Mode</strong>, <strong>Search Parameters</strong>, <strong>Auto Refresh</strong>, <strong>JSON Editor Mode</strong>) grouped together.</li><li><strong>Settings Management</strong> moved from the tab header.</li></ul><h4 id="network-2" tabindex="-1">Network <a class="header-anchor" href="#network-2" aria-label="Permalink to &quot;Network&quot;">​</a></h4><ul><li><strong>Search Settings</strong> split into their own section and decoupled.</li><li><strong>Breakpoints</strong> / <strong>Mocks</strong> table layout fixes — rows no longer over-stretch.</li><li>Toggle and edit existing rules.</li></ul><h4 id="props-2" tabindex="-1">Props <a class="header-anchor" href="#props-2" aria-label="Permalink to &quot;Props&quot;">​</a></h4><ul><li>Settings file controls moved into the section.</li><li><strong>Component Blacklist</strong> moved here from the general block.</li><li><strong>Favorite Components</strong> moved here from the general block.</li></ul><h4 id="pinia-store" tabindex="-1">Pinia Store <a class="header-anchor" href="#pinia-store" aria-label="Permalink to &quot;Pinia Store&quot;">​</a></h4><ul><li>Settings file controls moved into the section.</li></ul><h4 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h4><ul><li><p><strong>Release notes</strong> and <strong>Check for updates</strong> (extension only).</p></li><li><p>When an update exists:</p><ul><li><strong>Ignore</strong> silences this version until a newer one ships;</li><li><strong>Download</strong> fetches the app archive.</li></ul></li></ul><h2 id="_2-3-0-2026-03-16" tabindex="-1">[2.3.0] - 2026-03-16 <a class="header-anchor" href="#_2-3-0-2026-03-16" aria-label="Permalink to &quot;[2.3.0] - 2026-03-16&quot;">​</a></h2><h3 id="network-3" tabindex="-1">Network <a class="header-anchor" href="#network-3" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li><strong>Postman</strong> collection export from captured <strong>Network</strong> traffic.</li><li>Single-panel mode: <strong>Copy cURL</strong> replaced with a header context menu — <strong>Breakpoint</strong>, <strong>Mock</strong>, <strong>Copy cURL</strong>.</li><li>Right-click context menu on request detail header.</li></ul><hr><h3 id="props-3" tabindex="-1">Props <a class="header-anchor" href="#props-3" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Favorites and blacklist behavior fixes.</li><li>Blacklist applied during collection traversal (not only table filtering) — faster Props load.</li><li>Quick actions menu for <strong>Props</strong>.</li><li>Refresh open component in read mode.</li><li>Shortcut jump to favorites from the favorites counter.</li></ul><hr><h3 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h3><ul><li>Pinia <strong>favorites</strong> with shortcut navigation.</li><li>Quick actions menu for <strong>Pinia Store</strong>.</li><li>Refresh open entry in read mode.</li><li><strong>Options</strong> supports manual favorite entries with <strong>wildcards</strong>.</li></ul><hr><h3 id="options-1" tabindex="-1">Options <a class="header-anchor" href="#options-1" aria-label="Permalink to &quot;Options&quot;">​</a></h3><ul><li>User files now persist as local copies in app storage.</li><li><strong>Standalone</strong> uses dedicated local storage — settings survive relaunch and work across sites.</li><li>Tree JSON editor temporarily disabled — text mode only.</li></ul><h4 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h4><p><strong>Options → General → Customize</strong> adds theming:</p><ul><li><strong>Dark / Light</strong> color scheme;</li><li><strong>Image</strong> background (<strong>File / Link</strong>) with stills, <strong>GIF</strong>, <strong>MP4</strong>;</li><li><strong>Browse</strong> or pick from saved files;</li><li>Add by URL;</li><li><strong>Image Opacity</strong>, <strong>Blur</strong>, <strong>Noise Intensity / Opacity</strong>, <strong>Position (X / Y)</strong>, <strong>Scale</strong> (<strong>100–200%</strong>).</li></ul><hr><h3 id="ui-ux-1" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-1" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Responsive layout for smaller screens.</li><li>Wide layout: split list + details.</li><li>~<strong>1000px</strong> width collapses to single-panel.</li><li><strong>Esc</strong> closes panels/dialogs.</li><li><strong>Ctrl+F</strong> search in <strong>DevTools</strong> tab mode.</li><li>Loading skeletons for <strong>Props</strong> / <strong>Pinia</strong> tables instead of raw “Not found”.</li><li>Column visibility toggles for <strong>Props</strong>, <strong>Pinia</strong>, <strong>Network</strong>.</li><li>Chevron redesign for iframe open/close.</li><li>Table context menus (right-click).</li></ul><hr><h3 id="performance-1" tabindex="-1">Performance <a class="header-anchor" href="#performance-1" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Blacklist applied during Props tree pre-walk — faster data collection and tab load.</li></ul><hr><h3 id="fixes" tabindex="-1">Fixes <a class="header-anchor" href="#fixes" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li>JSON edit hit area while scrolling.</li><li><strong>Network</strong> tab freezes after long sessions.</li><li><strong>Ctrl+A</strong> selects only the focused input.</li><li>Reset/delete buttons respect <strong>disabled</strong> state.</li><li><strong>Options</strong> tables with many rows.</li><li>JSON edit mode styling.</li><li>Minor cosmetic fixes.</li></ul><h2 id="_2-4-0-2026-04-05" tabindex="-1">[2.4.0] - 2026-04-05 <a class="header-anchor" href="#_2-4-0-2026-04-05" aria-label="Permalink to &quot;[2.4.0] - 2026-04-05&quot;">​</a></h2><h3 id="network-4" tabindex="-1">Network <a class="header-anchor" href="#network-4" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>When <strong>Pause</strong> is enabled, inspector interceptors are detached, so native DevTools display the <strong>original initiator</strong> instead of <strong>injected.ts</strong>.</li><li>The <strong>Network</strong> table now uses virtualization for better performance and reduced UI freezes.</li><li>The request details view now opens on the <strong>Response</strong> tab by default.</li><li>When a <strong>Breakpoint</strong> is triggered, the paused method automatically opens on the <strong>Request</strong> tab.</li><li><strong>Search by</strong> lists on the <strong>Network</strong> tab and in <strong>Options</strong> now support searching by the <strong>Name</strong> column.</li></ul><hr><h3 id="props-4" tabindex="-1">Props <a class="header-anchor" href="#props-4" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li><p><strong>Props</strong> performance has been significantly improved, making <strong>auto refresh</strong> safe to use.</p></li><li><p>In the <strong>Props</strong> table, the <strong>Props</strong> column has been split into <strong>Passed</strong> and <strong>Declared</strong> (all columns can be hidden):</p><ul><li><strong>Passed</strong> — number of props currently received;</li><li><strong>Declared</strong> — number of props declared on the component.</li></ul></li><li><p>In the right-side <strong>Props details</strong> panel, data is now split into two tabs:</p><ul><li><strong>Passed</strong> — props currently received (opened by default);</li><li><strong>Declared</strong> — all props declared by the component.</li></ul></li><li><p>The <strong>Props details</strong> panel now includes a <strong>Size</strong> parameter.</p></li></ul><h4 id="inspect-props-inspector" tabindex="-1">Inspect (Props Inspector) <a class="header-anchor" href="#inspect-props-inspector" aria-label="Permalink to &quot;Inspect (Props Inspector)&quot;">​</a></h4><ul><li>Added page element selection mode similar to <strong>Chrome DevTools Elements</strong>.</li><li>Allows selecting elements directly on the page for quick <strong>Props</strong> filtering.</li><li>Highlights <strong>Vue</strong> components on hover.</li><li>Displays quick element info: <strong>Name</strong>, <strong>Root element</strong>, <strong>Received Props</strong>, <strong>Nested components</strong>.</li><li>After selection, <strong>Props</strong> displays only the selected element and its nested components.</li><li>The filter can be quickly cleared via the <strong>Filtered</strong> badge.</li></ul><hr><h3 id="ui-ux-2" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-2" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><h4 id="windowed-mode" tabindex="-1">Windowed mode <a class="header-anchor" href="#windowed-mode" aria-label="Permalink to &quot;Windowed mode&quot;">​</a></h4><ul><li>Added support for windowed mode with saved position for both launch modes.</li><li>Updated the iframe open chevron with a drag indicator.</li><li>Added support for docking the launcher to any of the four browser edges with automatic vertical stretching.</li></ul><h4 id="auto-launch-settings" tabindex="-1">Auto launch settings <a class="header-anchor" href="#auto-launch-settings" aria-label="Permalink to &quot;Auto launch settings&quot;">​</a></h4><ul><li><p>Added <strong>Whitelist</strong> for automatic app launch and <strong>Blacklist</strong> for excluded sites where launch and launcher display are disabled.</p></li><li><p>Added extension <strong>popup</strong> with quick actions:</p><ul><li><strong>Forced Launch</strong> — launches the app ignoring whitelist, blacklist, and static-site restrictions;</li><li><strong>Reset Settings</strong> — resets all extension settings.</li></ul></li></ul><h4 id="other-ui-improvements" tabindex="-1">Other UI improvements <a class="header-anchor" href="#other-ui-improvements" aria-label="Permalink to &quot;Other UI improvements&quot;">​</a></h4><ul><li>Fixed <strong>JSON</strong> styling for large data volumes.</li><li>Added exact search when entering values in quotes; without quotes, search works in <strong>like</strong> mode.</li><li>Minor visual interface improvements.</li><li>Improved <strong>Esc</strong> behavior in <strong>DevTools</strong> mode: first closes nested tabs, and when nothing else remains, opens the <strong>DevTools Console</strong>.</li></ul><hr><h3 id="performance-2" tabindex="-1">Performance <a class="header-anchor" href="#performance-2" aria-label="Permalink to &quot;Performance&quot;">​</a></h3><ul><li>Improved <strong>Props</strong> and <strong>Store</strong> detection mechanism for significantly faster data retrieval.</li><li>Increased limits for maximum readable <strong>Props</strong> count.</li><li>Refactored internal project structure: removed unused modules, dead code, and duplicated logic.</li></ul><hr><h3 id="documentation" tabindex="-1">Documentation <a class="header-anchor" href="#documentation" aria-label="Permalink to &quot;Documentation&quot;">​</a></h3><ul><li>Full project documentation has been added.</li><li>Added a <strong>Documentation</strong> section to the landing page.</li><li>Added quick documentation access via <strong>Options → About</strong>.</li></ul><hr><h3 id="fixes-1" tabindex="-1">Fixes <a class="header-anchor" href="#fixes-1" aria-label="Permalink to &quot;Fixes&quot;">​</a></h3><ul><li>Blocked native right-click menu inside the application context menu. • Fixed incorrect favorite detection in Props details when names matched.</li><li>Improved search behavior in <strong>DevTools mode</strong>: fixed cases where search could stop working and added highlight reset when clearing the field or closing search.</li><li>Fixed an issue when saving changes to <strong>Getters</strong> in <strong>Pinia Store</strong>.</li><li>Fixed an issue with retrieving <strong>Props</strong> data in <strong>Vue</strong> during local development.</li><li>Fixed <strong>Network</strong> issues during local development.</li></ul><h2 id="_2-5-0-2026-05-17" tabindex="-1">[2.5.0] - 2026-05-17 <a class="header-anchor" href="#_2-5-0-2026-05-17" aria-label="Permalink to &quot;[2.5.0] - 2026-05-17&quot;">​</a></h2><h3 id="network-5" tabindex="-1">Network <a class="header-anchor" href="#network-5" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Network header sections can be <strong>collapsed</strong> and <strong>expanded</strong>.</li><li>The app <strong>remembers the last details tab</strong> you used; when you open another request, it opens on the <strong>same tab</strong> you had selected while viewing the previous request.</li></ul><p><strong>Global suspend for Breakpoint and Mock</strong></p><p>On the <strong>Network</strong> toolbar (right side, next to log recording controls), two buttons were added: <strong>suspend / resume all breakpoint rules</strong> (pause-in-circle icon; active — <strong>amber</strong> accent) and <strong>suspend / resume all mock responses</strong> (shuffle icon; active — <strong>purple</strong> accent). Rules are <strong>not</strong> removed from <strong>Options → Network</strong>; when turned off, that interception type is <strong>not</strong> applied on the page. The same flags are controlled by <strong>Enable breakpoint rules</strong> and <strong>Enable mock responses</strong> next to the lists in <strong>Options</strong>; the toolbar and <strong>Options</strong> stay in sync. <strong>bp</strong> and <strong>mock</strong> badges use a <strong>muted</strong> style when global rule application is disabled.</p><p><strong>Network capture: Advanced mode</strong></p><p><strong>Network</strong> settings include <strong>Advanced mode</strong>: the extension requests additional permissions and collects the <strong>full</strong> request and response header set (including headers not always visible in the regular DevTools <strong>Network</strong> tab because of page limitations). <strong>Classic mode</strong> still shows only headers available in the standard “classic” view without bypassing those limitations.</p><p><strong>Standalone</strong></p><p>Advanced capture and related features are <strong>not available in Standalone</strong>: only the classic flow runs there, without extended headers and without Advanced-only menus and settings.</p><p><strong>What Advanced mode adds in Network</strong></p><ul><li><strong>Extra headers</strong> in the Request / Response areas on the selected request’s Headers tab.</li><li><strong>Pinned headers</strong> — pin names to the top of the list separately for <strong>request</strong> and <strong>response</strong>; edit pins in settings (Advanced only).</li><li><strong>Header links</strong> — per host and URL template, open an external resource with the header value substituted (e.g. traces, ID lookup, internal dashboards). Manage rules in <strong>Network</strong> settings and from the header row context menu (when Advanced).</li><li><strong>Header links</strong> and <strong>Pinned headers</strong> in <strong>Options</strong> are shown <strong>only when Advanced mode is enabled</strong> so Classic mode stays uncluttered.</li></ul><hr><h3 id="ui-ux-3" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux-3" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><p><strong>JSON Mode (<strong>Options → General</strong>)</strong></p><p><strong>Options → General</strong> now includes a <strong>JSON Mode</strong> switch with two options:</p><ul><li><strong>Classic</strong> — built-in text editor with Prism syntax highlighting (<strong>JsonTextEditor</strong>): a single text view with no tree, tuned for large payloads (reduced highlighting on very long JSON and a lightweight viewer for large non-JSON read-only bodies).</li><li><strong>Advanced</strong> — <strong>vanilla-jsoneditor</strong>: two views of the same JSON — <strong>Text</strong> (code) and <strong>Tree</strong> (structure); switch from the toolbar; the last selected mode (<strong>Text</strong> / <strong>Tree</strong>) is <strong>saved</strong> in settings (<strong>json.mode</strong>). Advanced provides <strong>Format</strong> / <strong>Compact</strong> (where editing is allowed), <strong>Undo / Redo</strong>, <strong>search</strong>, copy; in tree mode — expand/collapse, path navigation, context menus, and sort/edit flows built on the tree.</li></ul><p>The <strong>Classic / Advanced</strong> choice selects the JSON implementation across the UI (<strong>Network</strong> and <strong>Mock</strong> bodies, <strong>Pinia</strong> snapshots, JSON on <strong>Props</strong>, etc.). Non-JSON content still uses text view with highlighting where supported.</p>',106)])])}const p=t(s,[["render",i]]);export{u as __pageData,p as default};
